module RefModule(
    input clk,
    input rst,
    output [4:0] count
);

    reg [4:0] obf_counter_reg;

    always @(posedge clk) begin
        if (!rst) begin
            obf_counter_reg <= 5'b11111;
        end else begin
            obf_counter_reg <= obf_counter_reg - 1;
        end
    end

    assign count = obf_counter_reg;

endmodule
